class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

def find_triplet_with_sum(head, target_sum):
    if not head or not head.next or not head.next.next:
        return False

    current1 = head
    while current1:
        hash_set = set()
        current2 = current1.next
        while current2:
            complement = target_sum - current1.data - current2.data
            if complement in hash_set:
                return True
            hash_set.add(current2.data)
            current2 = current2.next
        current1 = current1.next

    return False

